          history.forEach(h => {
             const match = h.refBE.match(regex);
             if (match) {
                 const num = parseInt(match[1], 10);
                 if (!isNaN(num) && num > maxId) {
                     maxId = num;
                 }
             }
          });

          const nextRef = `BE-PNS-${String(maxId + 1).padStart(4, '0')}`;
