          pagebreak:    { mode: 'avoid-all' }
        };

        setIsExporting(true);
        element.classList.add('pdf-mode');

        // @ts-ignore
        if (window.html2pdf) {
            // @ts-ignore
            window.html2pdf().set(opt).from(element).save().then(() => {
                setIsExporting(false);
                element.classList.remove('pdf-mode');
                resolve();
            }).catch((err: any) => {
                setIsExporting(false);
                element.classList.remove('pdf-mode');
                reject(err);
            });
        } else {
            setIsExporting(false);
