                          </div>

                          {/* Observation / Response Info */}
                          <div className="bg-amber-50/50 p-4 rounded-lg border border-amber-100 space-y-4">
                              <h4 className="text-sm font-bold text-amber-800 uppercase tracking-wider mb-2">Réponse / Validation</h4>
                              <div>
                                  <label className="block text-xs font-semibold text-gray-500 mb-1">Statut Actuel</label>
                                  <select value={newStatus} onChange={e => setNewStatus(e.target.value as ApprovalStatus)} className="w-full p-2 border rounded focus:ring-2 focus:ring-amber-500 outline-none font-medium">
                                      <option value={ApprovalStatus.PENDING}>En attente / En cours</option>
                                      <option value={ApprovalStatus.APPROVED}>Approuvé (Bon pour Exécution)</option>
                                      <option value={ApprovalStatus.APPROVED_WITH_COMMENTS}>Approuvé avec Réserves</option>
                                      <option value={ApprovalStatus.REJECTED}>Rejeté / Refusé</option>
                                      <option value={ApprovalStatus.NO_RESPONSE}>Sans Réponse (Délai dépassé)</option>
                                  </select>
                              </div>
                              <div className="grid grid-cols-2 gap-4">
                                  <div>
                                      <label className="block text-xs font-semibold text-gray-500 mb-1">Date Réponse</label>
                                      <input type="date" value={newObservationDate} onChange={e => setNewObservationDate(e.target.value)} className="w-full p-2 border rounded focus:ring-2 focus:ring-amber-500 outline-none" />
                                  </div>
                                  <div>
                                      <label className="block text-xs font-semibold text-gray-500 mb-1">Réf. Note/Visa</label>
                                      <input value={newObservationRef} onChange={e => setNewObservationRef(e.target.value)} className="w-full p-2 border rounded focus:ring-2 focus:ring-amber-500 outline-none" placeholder="OBS-..." />
                                  </div>
                              </div>
                              {/* File List Obs */}
                              <div>
                                  <label className="block text-xs font-semibold text-gray-500 mb-1">Fichiers Annotés (Visa)</label>
                                  {newObservationFiles.map((file, idx) => (
                                      <div key={idx} className="flex items-center gap-2 text-xs bg-white border p-1 rounded mb-1">
                                          <span className="truncate flex-1">Note {idx + 1}</span>
                                          <button type="button" onClick={() => setAttachmentToDelete({ type: 'observation', index: idx })} className="text-red-500"><X size={12}/></button>
