                                  {newObservationFiles.length < 3 && (
                                    <div className="relative mt-2">
                                        <input type="file" id="obs-upload" className="hidden" onChange={(e) => handleModalFileChange(e, 'observation')} />
                                        <label htmlFor="obs-upload" className="flex items-center justify-center gap-2 w-full p-2 border-2 border-dashed border-gray-300 rounded text-gray-500 hover:border-amber-500 hover:text-amber-500 cursor-pointer text-xs">
                                            <UploadCloud size={14} /> Ajouter Note/Visa
                                        </label>
                                    </div>
                                  )}
                              </div>
                          </div>
                      </div>

                      <div className="flex justify-end gap-3 pt-4 border-t border-gray-200">
                          <button type="button" onClick={closeAllModals} className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg font-medium">Annuler</button>
                          <button type="submit" className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 font-bold shadow-sm flex items-center gap-2">
                              <Save size={18} /> Enregistrer
                          </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* --- CONFIRMATION MODALS --- */}
      {deleteConfirmId && (
          <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center p-4 backdrop-blur-sm">
              <div className="bg-white rounded-lg p-6 max-w-sm w-full shadow-2xl">
                  <h3 className="text-lg font-bold text-gray-800 mb-2">Confirmer la suppression</h3>
                  <p className="text-gray-600 text-sm mb-6">Êtes-vous sûr de vouloir supprimer ce document ? Cette action est irréversible.</p>
                  <div className="flex justify-end gap-3">
                      <button onClick={() => setDeleteConfirmId(null)} className="px-4 py-2 border rounded hover:bg-gray-50">Annuler</button>
                      <button onClick={confirmDelete} className="px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700">Supprimer</button>
                  </div>
              </div>
          </div>
      )}

      {attachmentToDelete && (
          <div className="fixed inset-0 bg-black/50 z-[70] flex items-center justify-center p-4">
              <div className="bg-white rounded-lg p-6 max-w-sm w-full shadow-2xl">
                  <h3 className="font-bold mb-4">Supprimer la pièce jointe ?</h3>
                  <div className="flex justify-end gap-3">
                      <button onClick={() => setAttachmentToDelete(null)} className="px-4 py-2 border rounded">Non</button>
                      <button onClick={confirmAttachmentDelete} className="px-4 py-2 bg-red-600 text-white rounded">Oui</button>
                  </div>
              </div>
          </div>
      )}

      {/* --- REMINDER MODAL --- */}
      {reminderModal && (
          <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center p-4 backdrop-blur-sm">
              <div className="bg-white rounded-xl p-6 max-w-sm w-full shadow-2xl border-t-4 border-amber-500">
                  <div className="flex items-center gap-2 mb-4 text-amber-600 font-bold text-lg">
                      <BellRing /> Configurer le Rappel
                  </div>
                  <div className="space-y-4">
                      <div className="flex items-center justify-between">
                          <label className="font-medium text-gray-700">Activer le rappel</label>
                          <input 
                              type="checkbox" 
                              checked={reminderForm.active} 
                              onChange={e => setReminderForm({...reminderForm, active: e.target.checked})} 
                              className="w-5 h-5 text-amber-600 rounded focus:ring-amber-500"
                          />
                      </div>
                      {reminderForm.active && (
                          <div>
                              <label className="block text-sm font-medium text-gray-700 mb-1">Fréquence de relance (jours)</label>
                              <input 
                                  type="number" 
                                  min="1"
                                  value={reminderForm.frequencyDays}
                                  onChange={e => setReminderForm({...reminderForm, frequencyDays: parseInt(e.target.value)})}
                                  className="w-full p-2 border border-gray-300 rounded focus:ring-2 focus:ring-amber-500 outline-none"
                              />
                              <p className="text-xs text-gray-500 mt-2 flex items-center gap-1">
                                  <Clock size={12}/> Prochaine relance prévue dans {reminderForm.frequencyDays} jours.
                              </p>
                          </div>
                      )}
                  </div>
                  <div className="flex justify-end gap-3 mt-6">
                      <button onClick={() => setReminderModal(null)} className="px-4 py-2 text-gray-500 hover:bg-gray-100 rounded">Fermer</button>
                      <button onClick={saveReminder} className="px-4 py-2 bg-amber-600 text-white rounded hover:bg-amber-700 font-medium shadow-sm">Enregistrer</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BTPDocument, ApprovalStatus } from '../types';
import { Square, CheckSquare, Archive, History, Trash2, Eye, X, AlertTriangle, CheckCircle, FileText, Printer, User, Users, Calendar, Hash, FileInput, PenTool, FileType, ChevronRight, Briefcase, Settings2, DownloadCloud, Search, Filter, ListPlus, MinusCircle, PlusCircle, Mic, MicOff, Plus, CloudLightning } from 'lucide-react';
import { Logo } from './Logo';
import { Document, Packer, Paragraph, Table, TableRow, TableCell, WidthType, TextRun, ImageRun, BorderStyle, AlignmentType, VerticalAlign, Header } from 'docx';
import { sendToGoogleScript } from '../services/googleService';

interface BordereauViewProps {
  documents: BTPDocument[];
  onAddDocument: (doc: BTPDocument) => void;
  onUpdateDocument: (doc: BTPDocument) => void;
  onDeleteDocument: (id: string) => void;
  selectedDocs: string[];
  setSelectedDocs: React.Dispatch<React.SetStateAction<string[]>>;
}

interface Stakeholder {
    name: string;
    contacts: string[];
}

interface SavedBordereau {
    id: string;
    refBE: string;
    date: string;
    recipient: string;
    project: string;
    documentCount: number;
    // Updated structure to include metadata for full code generation
    documents: { 
        id?: string; 
        code: string; 
        name: string; 
        index: string;
        lot?: string;
        poste?: string;
        classement?: string;
    }[];
    observations: Record<string, string>;
    copies: Record<string, number>;
    formDataSnapshot: any;
    timestamp: number;
}

const INTERNAL_DEPARTMENTS = [
    "Bureau d'Études",
    "Direction Technique",
    "Conduite de Travaux",
    "Service QHSE",
    "Direction Générale",
    "Service Achats"
];

export const BordereauView: React.FC<BordereauViewProps> = ({ 
    documents, 
    onAddDocument, 
    onDeleteDocument,
    selectedDocs,
    setSelectedDocs
}) => {
  const [isExporting, setIsExporting] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false); // New State for Google Sync
  const [logo, setLogo] = useState('');
  const [googleScriptUrl, setGoogleScriptUrl] = useState('');

  // Search & Filter State for Document Selection
  const [searchTerm, setSearchTerm] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [statusFilter, setStatusFilter] = useState<ApprovalStatus | 'ALL'>('ALL');

  // History State
  const [history, setHistory] = useState<SavedBordereau[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [historySearchTerm, setHistorySearchTerm] = useState('');

  // PDF Preview State (History)
  const [previewBordereau, setPreviewBordereau] = useState<SavedBordereau | null>(null);

  // New Document Modal State
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [deleteDocConfirmId, setDeleteDocConfirmId] = useState<string | null>(null);
  const [newDocForm, setNewDocForm] = useState({
      lot: '01',
      code: '',
      name: '',
      index: '00',
      status: ApprovalStatus.PENDING,
      transmittalDate: new Date().toISOString().slice(0, 10)
  });

  // Loaded Settings
  const [stakeholders, setStakeholders] = useState<{
    client: Stakeholder;
    consultant: Stakeholder;
    control: Stakeholder;
  } | null>(null);

  // Form State
  const [formData, setFormData] = useState({
    ref: 'FR80', // Keep for compatibility but not used in display
    date: new Date().toISOString().slice(0, 10), // Used for "Date d'envoi", NOT the form date
    version: 'B', // Keep for compatibility but not used in display
    project: 'Construction Siège Horizon',
    from: "Bureau d'Études", // Default
    to: '', // Destinataire
    attn: '', // Attention
    object: 'Soumission des plans pour exécution',
    refBE: 'BE-PNS-0001', // Default starting value
    sender: 'Chef de Projet',
    recipient: 'Client',
    companyName: 'Société Bouzguenda Frères',
    companySubtitle: 'Entreprise Générale de Bâtiments et de Travaux Publics',
    address: '41 Rue 8600 ZI La Charguia 1. Tunis',
    contact: 'Tél. : 70 557 900 - Fax : 70 557 999',
  });

  const [docObs, setDocObs] = useState<Record<string, string>>({});
  const [docCopies, setDocCopies] = useState<Record<string, number>>({});

  // Derived state for available contacts based on selected recipient
  const availableContacts = React.useMemo(() => {
      if (!stakeholders || !formData.to) return [];

      // On cherche quel acteur correspond au nom sélectionné
      if (stakeholders.client.name === formData.to) return stakeholders.client.contacts;
      if (stakeholders.consultant.name === formData.to) return stakeholders.consultant.contacts;
      if (stakeholders.control.name === formData.to) return stakeholders.control.contacts;

      // Fallback
      const st = (Object.values(stakeholders) as Stakeholder[]).find(s => s.name === formData.to);
      return st ? st.contacts : [];
  }, [stakeholders, formData.to]);

  const loadSettings = () => {
    const savedSettings = localStorage.getItem('btp-app-settings');
    if (savedSettings) {
        const parsed = JSON.parse(savedSettings);

        // Initial defaults if not set
        const defaultStakeholders = {
            client: { name: 'Maître d\'Ouvrage', contacts: [] },
            consultant: { name: 'Bureau d\'Études', contacts: [] },
            control: { name: 'Bureau de Contrôle', contacts: [] }
        };

        const loadedStakeholders = parsed.stakeholders || defaultStakeholders;

        setStakeholders(loadedStakeholders);

        setFormData(prev => ({
            ...prev,
            project: parsed.projectName || prev.project,
            // Si le destinataire actuel n'est pas dans la liste, on ne force pas le changement, sauf si vide
            to: prev.to || loadedStakeholders.control?.name || '',
            companyName: parsed.companyName || prev.companyName,
            companySubtitle: parsed.companySubtitle || prev.companySubtitle,
            address: parsed.address || prev.address,
            contact: parsed.contact || prev.contact
        }));
        if (parsed.logo) setLogo(parsed.logo);
        if (parsed.googleScriptUrl) setGoogleScriptUrl(parsed.googleScriptUrl);
    }
  };

  const loadHistory = () => {
      const savedHistory = localStorage.getItem('btp-bordereau-history');
      if (savedHistory) {
          setHistory(JSON.parse(savedHistory));
      }
  };

  // Recalculate Ref BE when history changes
  useEffect(() => {
      if (history.length >= 0) {
          let maxId = 0;
          // Regex to find BE-PNS-XXXX pattern
          const regex = /^BE-PNS-(\d{4})$/;

          history.forEach(h => {
             const match = h.refBE.match(regex);
             if (match) {
                 const num = parseInt(match[1], 10);
                 if (!isNaN(num) && num > maxId) {
                     maxId = num;
                 }
             }
          });

