                         if (!('index' in doc) && 'revisions' in doc) {
                              // @ts-ignore
                              const d = doc as BTPDocument;
                              const revIdx = (d.currentRevisionIndex !== undefined) ? d.currentRevisionIndex : d.revisions.length - 1;
                              const rev = d.revisions[revIdx];
                              code = d.code;
                              name = d.name;
