                           return (
                               <tr 
                                   key={doc.id} 
                                   className={`transition-all duration-200 cursor-pointer ${isSelected ? 'bg-amber-900/30 border-l-4 border-l-amber-500' : 'hover:bg-slate-700 border-l-4 border-l-transparent text-slate-300'}`}
