                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-xs font-bold text-slate-400 mb-1">Lot</label>
                            <input 
                                value={newDocForm.lot} 
                                onChange={e => setNewDocForm({...newDocForm, lot: e.target.value})} 
