                            Annuler
                        </button>
                        <button 
                            type="submit" 
                            className="px-4 py-2 bg-amber-600 text-white rounded-lg hover:bg-amber-700 text-sm font-bold shadow-sm"
                        >
                            Créer et Sélectionner
                        </button>
                    </div>
                </form>
            </div>
        </div>
      )}

      {/* DELETE DOCUMENT CONFIRMATION MODAL */}
