                                                      title="Voir PDF"
                                                  >
                                                      <FileText size={18} />
                                                  </button>
                                                  <button 
                                                      onClick={() => setDeleteConfirmId(item.id)}
                                                      className="text-red-400 hover:text-red-300 p-2 hover:bg-red-900/20 rounded transition-colors"
                                                      title="Supprimer"
                                                  >
                                                      <Trash2 size={18} />
                                                  </button>
                                              </div>
                                          </td>
                                      </tr>
                                  ))}
                              </tbody>
                          </table>
                      )}
                  </div>
              </div>
          </div>
