                                    }
                               }
                               setFormData({...formData, to: newTo, attn: newAttn});
                           }}
                       >
                           <option value="" disabled>Sélectionner...</option>
                           {stakeholders && (
                               <>
                                   {stakeholders.client.name && <option value={stakeholders.client.name}>{stakeholders.client.name} (Client)</option>}
